output.sparql:
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX bd: <http://www.bigdata.com/rdf#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?opponent ?opponentLabel WHERE {
  wd:Q24906838 wdt:P119 ?opponent .
  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en" .
  }
}

args.sparql:
SELECT ?opponent ?opponentLabel WHERE {
  wd:Q21189266 wdt:P341 wd:Q24906838 .
  wd:Q24906838 p:P2865 ?statement .
  ?statement ps:P2865 ?opponent .
  FILTER(?opponent != wd:Q1434) .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?opponent ?opponentLabel WHERE {
  wd:Q24906838 p:P2865 ?participant .
  ?participant ps:P2865 ?opponentSeason .
  FILTER(?opponentSeason != wd:Q21189266) .
  ?opponentSeason wdt:P176 ?opponent .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
